VALUES
  ('disabled-6f0ba476-moex-00291', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司X1年初開業，一向採「先進先出法」作為成本流動假設，報稅亦採 「先進先出法」。該公司擬自X3年1月1日改採「加權平均法」，不同方 法各年銷貨成本如下表，X3年的銷貨收入為$180,000，營業費用$40,000， 所得稅稅率為17%。試問此存貨方法改變相關會計紀錄何者正確？ 年度 先進先出法 加權平均法 X1 $ 74,000 $67,000 X2 90,000 83,000 X3 108,000 96,000', '["此為會計政策變動，X3年1月1日需認列追溯適用及追溯重編影響數， 分錄需借：存貨$11,620", "此為會計估計變動，不需追溯適用或追溯重編", "此為會計政策變動，X3年1月1日需認列追溯適用及追溯重編影響數， X3年1月1日分錄需借：存貨增加$14,000", "此為會計政策變動，X3年1月1日需認列追溯適用及追溯重編影響數， X3年1月1日分錄需借：存貨增加$26,000 30650"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00292', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司 X1 年 1 月 2 日以$942,919 購入乙公司發行之面額$1,000,000 公司 債做為「透過其他綜合損益按公允價值衡量之金融資產」，期末需依照市 價進行「透過其他綜合損益按公允價值衡量之金融資產評價調整」，按照 該票面利率3%，有效利率5.1%，3 年期，每年12 月31 日付息所編製的 折價攤銷表如下。X1 年12 月31 日該公司債市價為$970,000，甲公司X1 年會計報表表達「透過其他綜合損益按公允價值衡量之金融資產」帳面金 額和未實現利益何者正確？ 日期 借：現金 借：金融資產 貸：利息收入 帳面金額 X1/1/2 942,919 X1/12/31 30,000 18,089 48,089 961,008 X2/12/31 30,000 19,011 49,011 980,019 X3/12/31 30,000 19,981 49,981 1,000,000', '["資產負債表的資產： 「透過其他綜合損益按公允價值衡量之金融資產-公司債」帳面金額 $961,008 損益表的未實現利益： $8,992", "資產負債表的資產： 「透過其他綜合損益按公允價值衡量之金融資產-公司債」帳面金額 $961,008 資產負債表的股東權益項下「其他權益-金融資產未實現損益」 $8,992", "資產負債表的資產： 「透過其他綜合損益按公允價值衡量之金融資產-公司債」 $961,008 「透過其他綜合損益按公允價值衡量之金融資產評價調整」 8,992 帳面金額 $970,000 損益表的未實現利益： $8,992", "資產負債表的資產： 「透過其他綜合損益按公允價值衡量之金融資產-公司債」 $961,008 「透過其他綜合損益按公允價值衡量之金融資產評價調整」 8,992 帳面金額 $970,000 資產負債表的股東權益項下「其他權益-金融資產未實現損益」 $8,992 30650"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00293', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', 'X1 年 1 月 2 日乙公司以$2,162,218 發行 2,000 張公司債，面額$1,000，5 年期，每年6月30日及12月31日付息，票面利率10%，市場利率8%， 試問乙公司X1年1月2日的分錄為何？', '["現金 2,162,218 應付公司債 2,000,000 公司債溢價 162,218", "按攤銷後成本衡量之金融資產-公司債 2,162,218 現金 2,162,218", "現金 2,000,000 應付公司債 2,000,000", "按攤銷後成本衡量之金融資產-公司債 2,000,000 現金 2,000,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00294', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司存貨管理採用定期盤存制，X1年3月1日進貨$4,000，購買條件2/10, n/30，甲公司在X1 年3 月2 日支付3 月1 日進貨時的運費$150，甲公司3 月2日時發現商品不能正常運作，退回$200之商品，甲公司在X1年3月9 日支付剩餘積欠的貨款，試問甲公司購買這批貨的進貨成本為何？', '["$3,870", "$3,874", "$3,950", "$4,024"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00295', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '發放股票股利和股票分割對於股票面額、保留盈餘及股東權益的影響為何？', '["發放股票股利：每股面值增加，保留盈餘增加，股東權益增加 股票分割：每股面值增加，保留盈餘增加，股東權益增加", "發放股票股利：每股面值不變，保留盈餘減少，股東權益不變 股票分割：每股面值減少，保留盈餘不變，股東權益不變", "發放股票股利：每股面值減少，保留盈餘不變，股東權益不變 股票分割：每股面值不變，保留盈餘減少，股東權益不變", "發放股票股利：每股面值減少，保留盈餘減少，股東權益減少 股票分割：每股面值減少，保留盈餘減少，股東權益減少"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00296', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '假設無任何永久性差異或暫時性差異發生，甲公司X4年淨損失$2,800,000 ，其他各年度淨利如下表，假設規定損失可先前抵 2 年，再後抵 20 年， 則X4年底之所得稅利益為何？ X1年 X2年 X3年 X4年 X5年 X6年 課稅所得 $720,000 $680,000 $600,000 $(2,800,000) $560,000 $2,320,000 稅率 20% 22% 24% 26% 28% 30%', '["$293,600", "$444,800", "$738,400", "$728,000 30650"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00297', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司以成本$40,000，累計折舊$30,000之舊機器，交換乙公司一台公允價 值$50,000，預期耐用年限20年之新機器。交換時甲公司需支付乙公司現金 $43,000。若此交換具商業實質，則甲公司應記錄新機器之取得成本為：', '["$40,000", "$47,000", "$50,000", "$53,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00298', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '下列為甲公司X1年度資訊： 銷貨成本 $226,000 1月1日商品存貨 54,800 12月31日商品存貨 57,400 1月1日應付帳款 54,400 12月31日應付帳款 59,800 試問存貨付現數為何？', '["$218,000", "$228,800", "$223,200", "$234,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
