  ('disabled-6f0ba476-moex-00300', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '於現金股利發放日，收到採用權益法會計處理之關聯企業投資發放的現金 股利時，投資公司應作什麼處理？', '["貸：採用權益法之關聯企業損益之份額", "貸：股利收入", "貸：採用權益法之關聯企業投資", "貸：應收股利"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
